   use strict;
   use warnings;
   use PDF::API2;
   use Text::CSV;

   # Function to extract text from PDF
   sub extract_pdf_text {
       my ($pdf_path) = @_;

       # Open the PDF file
       my $pdf = PDF::API2->open($pdf_path);

       # Create a CSV object
       my $csv = Text::CSV->new({ binary => 1 });

       # Open a file to write the extracted data
       open(my $fh, '>', 'extracted_data.csv') or die "Could not open file 'extracted_data.csv' $!";

       # Loop through each page
       for my $page (1 .. $pdf->pages) {
           my $text = $pdf->page($page)->text;

           # Write the text to the CSV file
           $csv->print($fh, [$text]);
       }

       close($fh);
   }

   # Path to the PDF file
   my $pdf_path = 'example.pdf';

   # Extract text from the PDF
   extract_pdf_text($pdf_path);

   print "Extraction complete. Data saved to 'extracted_data.csv'.\n";
